import java.util.*;

public class Solution {
    // Optimal: monotonic increasing stack of indices. O(n) time, O(n) space.
    public int largestRectangleArea(int[] heights) {
        if (heights == null || heights.length == 0) {
            return 0;
        }

        int n = heights.length;
        long maxArea = 0;
        Deque<Integer> stack = new ArrayDeque<>(); // holds indices, heights increasing

        // Iterate one past the end with a virtual zero-height bar to flush the stack.
        for (int rightIndex = 0; rightIndex <= n; rightIndex++) {
            int currentHeight = (rightIndex == n) ? 0 : heights[rightIndex];

            // While the current bar is shorter than the bar on top of the stack,
            // that taller bar can't extend further right — finalize its rectangle.
            while (!stack.isEmpty() && heights[stack.peek()] >= currentHeight) {
                int poppedHeight = heights[stack.pop()];
                // Left boundary is the new top after popping (exclusive); right is rightIndex (exclusive).
                int leftBoundary = stack.isEmpty() ? -1 : stack.peek();
                long width = rightIndex - leftBoundary - 1;
                long area = (long) poppedHeight * width;
                maxArea = Math.max(maxArea, area);
            }
            stack.push(rightIndex);
        }

        return (int) maxArea;
    }

    // Brute force oracle: O(n^2). For each bar, expand left/right while >= its height.
    public int largestRectangleAreaBrute(int[] heights) {
        if (heights == null || heights.length == 0) {
            return 0;
        }
        int n = heights.length;
        long maxArea = 0;
        for (int i = 0; i < n; i++) {
            int h = heights[i];
            int left = i;
            while (left - 1 >= 0 && heights[left - 1] >= h) {
                left--;
            }
            int right = i;
            while (right + 1 < n && heights[right + 1] >= h) {
                right++;
            }
            long width = right - left + 1;
            maxArea = Math.max(maxArea, (long) h * width);
        }
        return (int) maxArea;
    }
}

import java.util.*;

public class Main {
    public static void main(String[] args) {
        Solution sol = new Solution();
        boolean allPass = true;

        // Test 1: LeetCode example -> 10
        allPass &= check(sol, new int[]{2, 1, 5, 6, 2, 3}, 10, "example");

        // Test 2: single bar
        allPass &= check(sol, new int[]{5}, 5, "single bar");

        // Test 3: single zero bar
        allPass &= check(sol, new int[]{0}, 0, "single zero");

        // Test 4: empty
        allPass &= check(sol, new int[]{}, 0, "empty");

        // Test 5: all equal -> n * h
        allPass &= check(sol, new int[]{3, 3, 3, 3}, 12, "all equal");

        // Test 6: strictly increasing -> best is last bar alone vs full width
        allPass &= check(sol, new int[]{1, 2, 3, 4, 5}, 9, "increasing");

        // Test 7: strictly decreasing
        allPass &= check(sol, new int[]{5, 4, 3, 2, 1}, 9, "decreasing");

        // Test 8: contains zeros splitting the histogram
        allPass &= check(sol, new int[]{2, 0, 2}, 2, "zeros split");

        // Test 9: two bars
        allPass &= check(sol, new int[]{2, 4}, 4, "two bars");

        // Test 10: valley shape
        allPass &= check(sol, new int[]{6, 2, 5, 4, 5, 1, 6}, 12, "valley");

        // Test 11: all zeros
        allPass &= check(sol, new int[]{0, 0, 0}, 0, "all zeros");

        // Test 12: overflow guard — large heights and width
        // 100000 bars of height 10000 -> area 1,000,000,000 (fits in int but near edge)
        int[] big = new int[100000];
        Arrays.fill(big, 10000);
        allPass &= check(sol, big, 1000000000, "max-area overflow guard");

        // Stress: brute-force oracle vs optimal on random inputs
        Random rng = new Random(42);
        for (int t = 0; t < 5000; t++) {
            int len = rng.nextInt(12) + 1;
            int[] arr = new int[len];
            for (int j = 0; j < len; j++) {
                arr[j] = rng.nextInt(6); // small values incl 0 for collisions
            }
            int opt = sol.largestRectangleArea(arr.clone());
            int brute = sol.largestRectangleAreaBrute(arr.clone());
            if (opt != brute) {
                allPass = false;
                System.out.println("STRESS MISMATCH " + Arrays.toString(arr)
                        + " opt=" + opt + " brute=" + brute);
            }
        }

        // Large stress for performance/no-crash at constraint size
        int[] perf = new int[100000];
        for (int i = 0; i < perf.length; i++) {
            perf[i] = rng.nextInt(10001);
        }
        long start = System.nanoTime();
        int perfRes = sol.largestRectangleArea(perf);
        long ms = (System.nanoTime() - start) / 1_000_000;
        System.out.println("perf n=100000 result=" + perfRes + " time=" + ms + "ms");

        System.out.println(allPass ? "ALL TESTS PASSED" : "SOME TESTS FAILED");
    }

    private static boolean check(Solution sol, int[] heights, int expected, String name) {
        int got = sol.largestRectangleArea(heights.clone());
        boolean ok = got == expected;
        System.out.println((ok ? "PASS" : "FAIL") + " [" + name + "] expected="
                + expected + " got=" + got);
        return ok;
    }
}
